def post_shopping_items(
    payload: ShoppingItemCreateRequest,
    session: Session = Depends(get_session),
) -> OperationResponse:
    item = shopping.add_item(session, payload.name, payload.actor_user_id)
    return OperationResponse(ok=True, id=item.id)


