) -> OperationResponse:
    try:
        override, notifications = cleaning.upsert_manual_swap(
            session,
            week_start=payload.week_start,
            member_a_id=payload.member_a_id,
            member_b_id=payload.member_b_id,
            actor_user_id=payload.actor_user_id,
