        const sourceLabel = sourceRange ? ` (${sourceRange})` : "";
        ctxParts.push(
          `Return shift. ${this._escape(historyAssigneeName)} is covering for ${this._escape(historyOriginalName || "the original assignee")} after a takeover${sourceLabel}.`
        );
